import socket
import network
import time
import json
import ubinascii
import uhashlib
import ustruct

class WebSocketServer:
    def __init__(self, ssid, password):
        self.ssid = ssid
        self.password = password
        self.socket = None
        self.clients = []
        
    def connect_wifi(self):
        sta_if = network.WLAN(network.STA_IF)
        if not sta_if.isconnected():
            sta_if.active(True)
            sta_if.connect(self.ssid, self.password)
            while not sta_if.isconnected():
                time.sleep(1)
        print('WiFi connected:', sta_if.ifconfig())
        
    def generate_accept_key(self, key):
        GUID = "258EAFA5-E914-47DA-95CA-C5AB0DC85B11"
        digest = uhashlib.sha1(key.encode() + GUID.encode()).digest()
        return ubinascii.b2a_base64(digest)[:-1].decode()
        
    def handle_client(self, client_socket, addr):
        try:
            request = client_socket.recv(1024).decode()
            if "Upgrade: websocket" in request:
                # Extract WebSocket key
                key_line = [line for line in request.split('\r\n') if 'Sec-WebSocket-Key:' in line]
                if key_line:
                    key = key_line[0].split(':')[1].strip()
                    accept_key = self.generate_accept_key(key)
                    
                    # Send WebSocket handshake response
                    response = f"HTTP/1.1 101 Switching Protocols\r\nUpgrade: websocket\r\nConnection: Upgrade\r\nSec-WebSocket-Accept: {accept_key}\r\n\r\n"
                    client_socket.send(response.encode())
                    
                    self.clients.append(client_socket)
                    print(f"New WebSocket client connected: {addr}")
                    
                    # Handle messages
                    while True:
                        try:
                            data = client_socket.recv(1024)
                            if not data:
                                break
                                
                            # Parse WebSocket frame
                            if len(data) > 2:
                                opcode = data[0] & 0x0F
                                if opcode == 1:  # Text frame
                                    message = data[2:].decode('utf-8')
                                    print(f"Received: {message}")
                                    try:
                                        cmd = json.loads(message)
                                        self.handle_command(cmd)
                                    except Exception as e:
                                        print(f"Error parsing JSON: {e}")
                        except Exception as e:
                            print(f"Client error: {e}")
                            break
        except Exception as e:
            print(f"Error handling client: {e}")
        finally:
            if client_socket in self.clients:
                self.clients.remove(client_socket)
            client_socket.close()
            print(f"Client {addr} disconnected")
            
    def handle_command(self, command):
        action = command.get('action', '')
        if action == 'turn_on':
            print("Turning ON")
        elif action == 'turn_off':
            print("Turning OFF")
        elif action == 'status':
            print("Status requested")
            
    def start_server(self):
        self.connect_wifi()
        
        self.socket = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        self.socket.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
        self.socket.bind(('0.0.0.0', 80))
        self.socket.listen(5)
        print("WebSocket server started on port 80")
        
        while True:
            try:
                client_socket, addr = self.socket.accept()
                print(f"Connection from {addr}")
                # Handle each client in a separate thread or process
                import _thread
                _thread.start_new_thread(self.handle_client, (client_socket, addr))
            except Exception as e:
                print(f"Server error: {e}")

# Usage
